namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class RecipeRating
{
    public int RecipeId { get; set; }
    public int Stars { get; set; }
    public int TotalRatings { get; set; }
    public double AverageRating { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly Dictionary<int, List<int>> _ratings = new();

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Description = "A simple and delicious pizza with fresh mozzarella and basil.", Ingredients = "Pizza dough
San Marzano tomatoes
Fresh mozzarella
Fresh basil
Olive oil
Salt", Steps = "1. Preheat oven to 475°F (245°C).
2. Roll out the dough on a floured surface.
3. Spread crushed tomatoes evenly.
4. Tear mozzarella and distribute over sauce.
5. Bake for 10-12 minutes until crust is golden.
6. Top with fresh basil and a drizzle of olive oil." },
            new() { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Description = "Creamy Roman pasta made with eggs, cheese, and pancetta.", Ingredients = "Spaghetti
Pancetta
Eggs
Pecorino Romano
Black pepper", Steps = "1. Cook spaghetti in salted boiling water.
2. Fry pancetta until crispy.
3. Whisk eggs with grated Pecorino and pepper.
4. Toss hot pasta with pancetta.
5. Remove from heat, stir in egg mixture.
6. Serve immediately with extra cheese." },
            new() { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Description = "Tender chicken in a creamy spiced tomato sauce.", Ingredients = "Chicken breast
Yogurt
Garam masala
Turmeric
Cumin
Tomato puree
Heavy cream
Onion
Garlic
Ginger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.
2. Grill or pan-fry chicken until charred.
3. Sauté onions, garlic, and ginger.
4. Add tomato puree and spices, simmer 15 min.
5. Stir in cream and cooked chicken.
6. Simmer 10 more minutes. Serve with rice." },
            new() { Id = 4, Title = "Vegetable Biryani", Category = "Indian", Description = "Fragrant layered rice dish with mixed vegetables.", Ingredients = "Basmati rice
Mixed vegetables
Onions
Yogurt
Biryani masala
Saffron
Mint leaves
Ghee", Steps = "1. Soak rice for 30 minutes, then parboil.
2. Fry sliced onions until golden.
3. Cook vegetables with spices and yogurt.
4. Layer rice and vegetables in a pot.
5. Add saffron milk and mint.
6. Cook on low heat (dum) for 25 minutes." },
            new() { Id = 5, Title = "Beef Tacos", Category = "Mexican", Description = "Seasoned ground beef in crispy corn tortillas.", Ingredients = "Ground beef
Taco seasoning
Corn tortillas
Lettuce
Tomato
Cheddar cheese
Sour cream
Salsa", Steps = "1. Brown ground beef in a skillet.
2. Add taco seasoning and water, simmer 5 min.
3. Warm tortillas in a dry pan.
4. Fill tortillas with seasoned beef.
5. Top with lettuce, tomato, cheese, sour cream.
6. Serve with salsa on the side." },
            new() { Id = 6, Title = "Guacamole", Category = "Mexican", Description = "Fresh avocado dip with lime and cilantro.", Ingredients = "Avocados
Lime juice
Cilantro
Red onion
Jalapeño
Tomato
Salt", Steps = "1. Halve and pit avocados.
2. Mash avocado to desired consistency.
3. Dice onion, tomato, and jalapeño.
4. Mix all ingredients together.
5. Add lime juice and salt to taste.
6. Serve immediately with tortilla chips." },
            new() { Id = 7, Title = "Miso Ramen", Category = "Japanese", Description = "Rich miso broth with noodles and toppings.", Ingredients = "Ramen noodles
Miso paste
Chicken broth
Soy sauce
Soft-boiled egg
Chashu pork
Green onions
Corn
Nori", Steps = "1. Simmer chicken broth with miso paste.
2. Season with soy sauce and mirin.
3. Cook ramen noodles according to package.
4. Slice chashu pork and prepare toppings.
5. Place noodles in bowl, ladle broth over.
6. Arrange toppings and serve hot." },
            new() { Id = 8, Title = "Teriyaki Salmon", Category = "Japanese", Description = "Glazed salmon fillets with sweet teriyaki sauce.", Ingredients = "Salmon fillets
Soy sauce
Mirin
Sake
Sugar
Ginger
Sesame seeds
Steamed rice", Steps = "1. Mix soy sauce, mirin, sake, and sugar for glaze.
2. Pan-sear salmon skin-side down 4 minutes.
3. Flip and cook 2 more minutes.
4. Pour teriyaki sauce into pan.
5. Baste salmon until glazed.
6. Serve over rice with sesame seeds." },
        };
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public RecipeRating GetRating(int recipeId)
    {
        if (!_ratings.ContainsKey(recipeId))
        {
            return new RecipeRating { RecipeId = recipeId, Stars = 0, TotalRatings = 0, AverageRating = 0 };
        }

        var ratings = _ratings[recipeId];
        return new RecipeRating
        {
            RecipeId = recipeId,
            TotalRatings = ratings.Count,
            AverageRating = ratings.Average()
        };
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;
        if (!_ratings.ContainsKey(recipeId))
        {
            _ratings[recipeId] = new List<int>();
        }
        _ratings[recipeId].Add(stars);
    }
}

