@page "/category/{CategoryName}"
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>
    <p class="lead">@Recipe.Description</p>

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><strong>🥘 Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients.Split('\n'))
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <div class="card">
                <div class="card-header"><strong>📝 Steps</strong></div>
                <div class="card-body">
                    @foreach (var step in Recipe.Steps.Split('\n'))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="mt-4">
        <h4>Rate this Recipe</h4>
        <StarRating RecipeId="@Recipe.Id" @rendermode="InteractiveServer" />
    </div>

    <a href="/category/@Recipe.Category" class="btn btn-secondary mt-3">← Back to @Recipe.Category Recipes</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetRecipeById(Id);
    }
}

@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= SelectedStars ? "selected" : "")"
              @onclick="() => Rate(star)"
              style="cursor: pointer; font-size: 1.5rem;">
            @(star <= SelectedStars ? "★" : "☆")
        </span>
    }

    @if (Rating.TotalRatings > 0)
    {
        <span class="ms-3 text-muted">
            @Rating.AverageRating.ToString("F1") avg · @Rating.TotalRatings rating(s)
        </span>
    }

    @if (JustRated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int SelectedStars { get; set; }
    private bool JustRated { get; set; }
    private RecipeRating Rating { get; set; } = new();

    protected override void OnParametersSet()
    {
        Rating = RecipeService.GetRating(RecipeId);
    }

    private void Rate(int stars)
    {
        SelectedStars = stars;
        RecipeService.AddRating(RecipeId, stars);
        Rating = RecipeService.GetRating(RecipeId);
        JustRated = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been added to the @Model.Category category.</p>
        <a href="/recipe/@SubmittedId" class="btn btn-primary">View Your Recipe</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label class="form-label">Recipe Title</label>
            <InputText class="form-control" @bind-Value="Model.Title" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect class="form-select" @bind-Value="Model.Category">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Mexican">Mexican</option>
                <option value="Japanese">Japanese</option>
                <option value="American">American</option>
                <option value="French">French</option>
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label class="form-label">Description</label>
            <InputText class="form-control" @bind-Value="Model.Description" placeholder="Brief description of the dish" />
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (one per line)</label>
            <InputTextArea class="form-control" rows="6" @bind-Value="Model.Ingredients" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea class="form-control" rows="8" @bind-Value="Model.Steps" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@(!IsValid)">Submit Recipe</button>
    </EditForm>
}

<a href="/" class="btn btn-secondary mt-3">← Back to Home</a>

@code {
    private Recipe Model { get; set; } = new();
    private bool Submitted { get; set; }
    private int SubmittedId { get; set; }

    private bool IsValid => !string.IsNullOrWhiteSpace(Model.Title)
        && !string.IsNullOrWhiteSpace(Model.Category)
        && !string.IsNullOrWhiteSpace(Model.Ingredients)
        && !string.IsNullOrWhiteSpace(Model.Steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;
        RecipeService.AddRecipe(Model);
        SubmittedId = Model.Id;
        Submitted = true;
    }

    private void Reset()
    {
        Model = new Recipe();
        Submitted = false;
    }
}

