                <option value="Indian">Indian</option>
                <option value="Mexican">Mexican</option>
                <option value="Japanese">Japanese</option>
                <option value="American">American</option>
                <option value="French">French</option>
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label class="form-label">Description</label>
            <InputText class="form-control" @bind-Value="Model.Description" placeholder="Brief description of the dish" />
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (one per line)</label>
            <InputTextArea class="form-control" rows="6" @bind-Value="Model.Ingredients" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea class="form-control" rows="8" @bind-Value="Model.Steps" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@(!IsValid)">Submit Recipe</button>
    </EditForm>
}

<a href="/" class="btn btn-secondary mt-3">← Back to Home</a>

@code {
    private Recipe Model { get; set; } = new();
    private bool Submitted { get; set; }
    private int SubmittedId { get; set; }

    private bool IsValid => !string.IsNullOrWhiteSpace(Model.Title)
        && !string.IsNullOrWhiteSpace(Model.Category)
        && !string.IsNullOrWhiteSpace(Model.Ingredients)
        && !string.IsNullOrWhiteSpace(Model.Steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;
        RecipeService.AddRecipe(Model);
        SubmittedId = Model.Id;
        Submitted = true;
    }

    private void Reset()
    {
        Model = new Recipe();
        Submitted = false;
    }
}
